UPDATE TEXTBOOK
SET
    TEXTBOOK_NM     = #{textbookNm}
    , PUBR_NM       = #{pubrNm, jdbcType=VARCHAR}
    , AUTHR_NM      = #{authrNm, jdbcType=VARCHAR}
    , ISBN_NO       = #{isbnNo, jdbcType=VARCHAR}
    , TRGT_GRD_CN   = #{trgtGrdCn, jdbcType=VARCHAR}
    , SUBJ_ID       = #{subjId, jdbcType=NUMERIC}
    , COURSE_SN     = #{courseSn, jdbcType=NUMERIC}
    , TAGLINE       = #{tagline, jdbcType=VARCHAR}
    , BOOK_SMRY     = #{bookSmry, jdbcType=VARCHAR}
    , TOC_CN        = #{tocCn, jdbcType=VARCHAR}
    , SALE_PRC_AMT  = #{salePrcAmt}
    , PURCH_PRC_AMT = #{purchPrcAmt, jdbcType=NUMERIC}
    , DLVR_AMT      = #{dlvrAmt, jdbcType=NUMERIC}
    , THMB_IMG      = #{thmbImg, jdbcType=VARCHAR}
    , LAST_MDFR_ID  = #{lastMdfrId}
    , MDFCN_DT      = CURRENT_TIMESTAMP
WHERE TEXTBOOK_SN = #{textbookSn}

UPDATE TEXTBOOK
SET
    USE_YN          = 'N'
    , LAST_MDFR_ID  = #{lastMdfrId}
    , MDFCN_DT      = CURRENT_TIMESTAMP
WHERE TEXTBOOK_SN = #{textbookSn}
